/// Linear interpolation between two depth maps.
pub fn lerp_depth(a: &[f32], b: &[f32], t: f32) -> Vec<f32> {
    let t = t.clamp(0.0, 1.0);
    a.iter().zip(b.iter()).map(|(&va, &vb)| va + (vb - va) * t).collect()
}

